// Sources the two build-time assets the docs site needs from their canonical homes, so
// there is never a committed copy to drift:
//
//   • internal/api/openapi.json → public/openapi.json   (the API reference reads this;
//     regenerated by `go generate ./internal/api`, so the docs always reflect the routes)
//   • web/public/mark.svg       → public/mark.svg        (favicon + hero logo)
//
// public/ is git-ignored: it is entirely reproduced by this script on every build.
import { mkdirSync, copyFileSync, existsSync } from 'node:fs'
import { fileURLToPath } from 'node:url'
import { dirname, resolve } from 'node:path'

const here = dirname(fileURLToPath(import.meta.url)) // site/scripts
const repo = resolve(here, '..', '..')               // repo root
const pub = resolve(here, '..', 'public')            // site/public

const assets = [
  { from: resolve(repo, 'internal/api/openapi.json'), to: resolve(pub, 'openapi.json') },
  { from: resolve(repo, 'web/public/mark.svg'), to: resolve(pub, 'mark.svg') },
]

mkdirSync(pub, { recursive: true })
for (const { from, to } of assets) {
  if (!existsSync(from)) {
    console.error(`[prebuild] missing source: ${from}`)
    process.exit(1)
  }
  copyFileSync(from, to)
  console.log(`[prebuild] ${from.replace(repo + '/', '')} → public/${to.split('/').pop()}`)
}
